-- GOLF & COUNTRY CLUBS
insert into businesses (name, slug, category_id, subcategory_id, area_id, address_line, short_description, description, phone, website, opening_hours_text, price_range, google_rating, google_review_count, featured, verified, verification_status, status, source_url, published_at)
values ('Windsor Golf Hotel & Country Club','windsor-golf-hotel-country-club',(select id from categories where slug='leisure-outdoors'),(select s.id from subcategories s join categories c on s.category_id=c.id where c.slug='leisure-outdoors' and s.slug='golf-country-clubs'),(select id from areas where slug='ridgeways'),'Kigwa Lane, off Kiambu Road, Ridgeways','Nairobi''s premier 18-hole golf club, luxury hotel, spa, tennis, pool, and multiple dining outlets in a forested setting.','Windsor Golf Hotel & Country Club is Nairobi''s premier leisure destination off Kiambu Road. Features an 18-hole championship golf course, luxury hotel rooms and suites, a spa, heated swimming pool, tennis courts, squash, a gym, and multiple restaurants and bars set in a stunning forested estate.','+254722203361','https://windsorgolfresort.com','Daily (members & guests)','$$$$'::price_range,4.5,1240,true,true,'verified'::verification_status,'published'::content_status,'https://windsorgolfresort.com',now())
on conflict (slug) do nothing;

insert into businesses (name, slug, category_id, subcategory_id, area_id, address_line, short_description, description, phone, website, opening_hours_text, price_range, google_rating, google_review_count, featured, verified, verification_status, status, source_url, published_at)
values ('Kiambu Golf Club','kiambu-golf-club',(select id from categories where slug='leisure-outdoors'),(select s.id from subcategories s join categories c on s.category_id=c.id where c.slug='leisure-outdoors' and s.slug='golf-country-clubs'),(select id from areas where slug='kiambu-town'),'Golf Road, Kiambu Town','Established 18-hole golf club in Kiambu Town. Public tee-times welcome, club hire available, colonial-era clubhouse.','Kiambu Golf Club is one of Kenya''s oldest golf clubs, established in the early 20th century and set in the scenic Kiambu highlands. Features an 18-hole grass-green course, a colonial-era clubhouse, a restaurant, and bar. Public tee-times available on weekdays; club hire on request.','+254722111222','https://kiambugolfclub.co.ke','Daily 6:00 AM – 6:00 PM','$$$'::price_range,4.3,320,true,true,'verified'::verification_status,'published'::content_status,'https://kiambugolfclub.co.ke',now())
on conflict (slug) do nothing;

-- PARKS & NATURE
insert into businesses (name, slug, category_id, subcategory_id, area_id, address_line, short_description, description, phone, website, opening_hours_text, price_range, google_rating, google_review_count, featured, verified, verification_status, status, source_url, published_at)
values ('Karura Forest','karura-forest',(select id from categories where slug='leisure-outdoors'),(select s.id from subcategories s join categories c on s.category_id=c.id where c.slug='leisure-outdoors' and s.slug='parks-nature'),(select id from areas where slug='runda'),'Kiambu Road / Limuru Road entrance, Runda','1,000+ acre urban forest adjacent to Kiambu Road. Trails for walking, cycling, and running. Waterfalls, caves, and picnic sites.','Karura Forest is a 1,041-acre indigenous urban forest at the intersection of Kiambu and Limuru Roads. Managed by the Kenya Forest Service and Friends of Karura, it offers well-maintained trails for walking, running, and cycling, a waterfall, caves, picnic sites, and abundant birdlife.','+254722828282','https://karuraforest.org','Daily 6:00 AM – 6:00 PM','$'::price_range,4.7,2800,true,true,'verified'::verification_status,'published'::content_status,'https://karuraforest.org',now())
on conflict (slug) do nothing;

