values ('Two Rivers Leisure Park','two-rivers-leisure-park',(select id from categories where slug='leisure-outdoors'),(select s.id from subcategories s join categories c on s.category_id=c.id where c.slug='leisure-outdoors' and s.slug='parks-nature'),(select id from areas where slug='two-rivers'),'Two Rivers Mall, Northern Bypass / Limuru Road','Riverside park adjacent to Two Rivers Mall. Walking paths, kids' play area, outdoor events space, and the Athi-Galana riverwalk.','The Two Rivers Leisure Park is an outdoor recreational area alongside Two Rivers Mall, set on the banks of a scenic river. Features walking and jogging paths, a children''s play area, open-air event space, a riverwalk, and weekend markets.','+254709432000','Daily 6:00 AM – 8:00 PM','$'::price_range,4.3,420,true,true,'verified'::verification_status,'published'::content_status,now())
